    def test_ticket_compliance(self):
        input_data = {'review': {
            'ticket_compliance_check': [
                {
                    'ticket_url': 'https://example.com/ticket/123',
                    'ticket_requirements': '- Requirement 1\n- Requirement 2\n',
                    'fully_compliant_requirements': '- Requirement 1\n- Requirement 2\n',
                    'not_compliant_requirements': '',
                    'requires_further_human_verification': '',
                }
            ]
        }}

        expected_output = textwrap.dedent("""\
            ## PR Reviewer Guide 🔍

            Here are some key observations to aid the review process:

            <table>
            <tr><td>

            **🎫 Ticket compliance analysis ✅**



            **[123](https://example.com/ticket/123) - Fully compliant**

            Compliant requirements:

            - Requirement 1
            - Requirement 2



            </td></tr>
            </table>
        """)

        assert convert_to_markdown_v2(input_data).strip() == expected_output.strip()

    def test_ticket_compliance_is_rendered_after_score_with_note(self):
        input_data = {'review': {
            'estimated_effort_to_review_[1-5]': '3',
            'score': '78/100',
            'ticket_compliance_check': [
                {
                    'ticket_url': 'https://example.com/ticket/FAKE-1234',
                    'ticket_requirements': '- Requirement 1\n',
                    'fully_compliant_requirements': '',
                    'not_compliant_requirements': '- Requirement 1\n',
                    'requires_further_human_verification': '',
                }
            ],
            'relevant_tests': 'Yes',
        }}

        result = convert_to_markdown_v2(
            input_data,
            ticket_note='PR title references Jira ticket `FAKE-1234` but branch name references `MOCK-5678`.',
        )

        assert '**🎫 Ticket compliance analysis ❌**' in result
        assert result.index('<strong>Score</strong>') < result.index('**🎫 Ticket compliance analysis ❌**')
        assert result.index('PR title references Jira ticket `FAKE-1234`') < result.index('**[FAKE-1234]')

    def test_ticket_compliance_ignores_placeholder_bullets(self):
        input_data = {'review': {
            'ticket_compliance_check': [
                {
                    'ticket_url': 'https://example.com/ticket/FAKE-1234',
                    'ticket_requirements': '',
                    'fully_compliant_requirements': '-\n',
                    'not_compliant_requirements': '- Requirement 1\n',
                    'requires_further_human_verification': '-\n',
                }
            ]
        }}

        result = convert_to_markdown_v2(input_data)

        assert '**🎫 Ticket compliance analysis ❌**' in result
        assert 'Compliant requirements:' not in result
