    def test_ticket_compliance_filters_placeholder_lines_from_mixed_content(self):
        input_data = {'review': {
            'ticket_compliance_check': [
                {
                    'ticket_url': 'https://example.com/ticket/FAKE-1234',
                    'ticket_requirements': '',
                    'fully_compliant_requirements': '- Requirement 1\n-\n',
                    'not_compliant_requirements': '*\n- Requirement 2\n',
                    'requires_further_human_verification': '',
                }
            ]
        }}

        result = convert_to_markdown_v2(input_data)

        assert '- Requirement 1' in result
        assert '- Requirement 2' in result
        assert '\n-\n' not in result
        assert '\n*\n' not in result

